#!/bin/bash
set -e
echo "=== EnergieSim installatie ==="
mkdir -p /var/www/energie-tool
cd /var/www/energie-tool

cat > server.js << 'B64EOF'

B64EOF
echo 'server.js geplaatst'

cat > index.html << 'B64EOF'

B64EOF
echo 'index.html geplaatst'

cat > zonneplan-api.js << 'B64EOF'

B64EOF
echo 'zonneplan-api.js geplaatst'

cat > energyzero-api.js << 'B64EOF'

B64EOF
echo 'energyzero-api.js geplaatst'

cat > package.json << 'B64EOF'

B64EOF
echo 'package.json geplaatst'

cat > Procfile << 'B64EOF'
d2ViOiBub2RlIHNlcnZlci5qcwo=
B64EOF
echo 'Procfile geplaatst'

npm install 2>/dev/null || true

if ! command -v pm2 &> /dev/null; then npm install -g pm2 2>/dev/null; fi
pm2 delete energie-tool 2>/dev/null || true
pm2 start server.js --name energie-tool
pm2 save

echo ""
echo "=== GELUKT! ==="
echo "Server draait op poort 3000"
echo "Open http://<VPS-IP>:3000 in de browser"
